var e=JSON.parse(`[{"id":"L6_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"괜찮은 거야, 저거? 벌써 국시만 열 그릇은 먹은 것 같은데?","JPN":"あれ大丈夫なの？　もう10回はおかわりしてるわよ。","ENG":"Is that all right? She looks like she has already put away ten bowls of noodle soup.","TWN":"牠還好嗎？光是麵條好像就已經吃了十碗？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_SHAKING_COCK"},{"id":"L7_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"성장기면 그럴 수도 있지. 요즘 애들은 많이 먹잖아.","JPN":"成長期は仕方ない。最近の子どもはたくさん食べるじゃないか。","ENG":"If she is still growing, sure. Kids these days can really pack it away.","TWN":"成長期也是情有可原，最近的孩子都吃很多。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"아니, 우리 식비 괜찮냐고.","JPN":"違うわよ、私たちの食費大丈夫なのかって意味よ。","ENG":"No, I mean can we afford the grocery bill?","TWN":"不，我是問我們的伙食費還好嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"……좀 굶지, 뭐.","JPN":"……まあ、しばらくは質素に過ごすしかないな。","ENG":"...We will tighten our belts a bit.","TWN":"……反正就餓肚子吧。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"푸하-. 시린그라드식 냉우동도 제법 별미구나.","JPN":"ぷはー、シリングラード流の冷やしうどんもなかなかいけるのう。","ENG":"Phew. Ciringrad-style cold udon is quite a treat.","TWN":"噗哈–錫林格勒式冷烏龍麵也別有一番風味呢。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_SHAKING_COCK"},{"id":"L14_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"큰일을 한 것도 아닌데 이런 대접이라니. 역시 시골 인심이 좋구만.","JPN":"大したこともしてないのに、こんなにもてなされるとは。田舎の情とはいいものじゃ。","ENG":"I didn't even do anything huge, yet you are treating me like royalty. Country hospitality is something else.","TWN":"我們也沒做什麼大事，居然受到這樣的待遇，鄉下果然很有人情味。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"이정도로 뭘. 오히려 마을 사정 탓에 환대를 못해줘서 미안할 따름이야.","JPN":"どういたしまして。村の事情で、もっといいものを出してあげられなくて逆に申し訳ないわ。","ENG":"This is nothing. If anything, I'm sorry we can't give you a proper welcome with how things are in the village.","TWN":"這點小事沒什麼，反而是因為村子的事沒能熱情款待妳們，覺得很抱歉。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"들었다. 북방합의체로 인해 마을 안에서 소동이 있었다지.","JPN":"話は聞いておるぞ。北方合意体のせいで村で騒ぎがあったそうじゃな。","ENG":"I heard there was a commotion in town because of the Northern Union.","TWN":"我聽說了，北方和議會在村子裡引發一陣騷亂。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"응? 그걸 어떻게…?","JPN":"え？　どうしてそれを……","ENG":"Huh? How did you know...?","TWN":"嗯？妳怎麼知道…？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"내가 오래 산 편이라 발이 좀 넓거든.","JPN":"長く生きているからか顔が広くてのう。","ENG":"I have been around a long time, so my network is wide.","TWN":"因為我活了很久，所以人脈比較廣。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"좋은 관계는 아니지만, 옛 전우의 자식에게서 여러가지 소식을 들었다.","JPN":"いい関係ではないが、古き戦友の子から色々聞かせてもらったのじゃ。","ENG":"We are not on good terms, but I heard plenty from an old comrade's child.","TWN":"雖然不是友好關係，但我從以前戰友的孩子那裡聽到許多消息。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"내가 찾고 있는 녀석이 이 마을에 체류하고 있다는 것도 말이야.","JPN":"わしが探しているやつがこの村に滞在していることもな。","ENG":"Including that the one I am looking for is staying in this village.","TWN":"還聽說我在找的傢伙滯留在這個村子裡。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"뭐야, 그런 거라면 진작 말하지.","JPN":"何よ、そんなことだったら最初から言ってくれればいいのに。","ENG":"Well then you should have said so sooner.","TWN":"什麼？這種事妳應該早點說。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"어떤 사람이야? 이름을 말해주면 우리가 불러올게.","JPN":"誰なの？　名前を教えてくれたら呼んでくるわ。","ENG":"Who is it? Tell me the name and we will call her over.","TWN":"是什麼樣的人？說出名字的話，我們會叫過來。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"아, 북방합의체의 레노어라는 녀석이다.","JPN":"あ、北方合意体のレノアというやつじゃ。","ENG":"A Northern Union woman named Lenore.","TWN":"啊，是北方和議會一個叫蕾諾雅的傢伙。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"으, 응…? 레노어?","JPN":"う、うん……？　レノア？","ENG":"H-huh...? Lenore?","TWN":"呃、嗯…？蕾諾雅？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L36_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"…가족은 아닌 것 같은데, 목적은?","JPN":"……家族ではないようだが、目的は？","ENG":"...You aren't family, so what is your purpose?","TWN":"…妳好像不是她的家人，目的是什麼？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"얻어맞은 만큼 팬 뒤, 내가 속한 가문연합으로 데려갈 거다.","JPN":"やられた分やり返してから、わしが所属している連合につれて帰るつもりじゃ。","ENG":"I plan to pay her back for every hit and take her to the Family Alliance.","TWN":"她先前怎麼修理我，我要全部奉還，然後把她帶到我所屬的家族聯盟。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"녀석의 힘이 가문연합에서 비롯되었으니, 클론과 다른 길을 가려는 시점에서 방치할 수는 없지.","JPN":"やつの力は連合から生まれたもの。クローンとは違う道を歩もうとしている以上、放置するわけにはいかん。","ENG":"Her power comes from the Family Alliance. If she is trying to walk a path different from the clone, I cannot just leave her be.","TWN":"她的力量是源自於家族聯盟，在這個要和複製人走上不同道路的時候，總不能置之不理。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"가문연합이라고…?","JPN":"連合……？","ENG":"The Family Alliance...?","TWN":"家族聯盟…？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"무슨 일이야, 안드레이?","JPN":"どうしたの、アンドレイ？","ENG":"What is it, Andrei?","TWN":"怎麼回事，安德烈？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L46_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"여, 연구소 출입금지 구역의 전력이 재가동됐어!","JPN":"け、研究所の立入禁止エリアの電力が再稼働した！","ENG":"Hey, the power in the lab's off-limits sector just came back online!","TWN":"研、研究所禁止進入區域的電力重新啟動了！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"지금 시간에는 갈 사람이 없을 텐데, 어째서?","JPN":"この時間にそこに行く者はいないはずなのに、なぜだ？","ENG":"At this hour no one should be there. Why now?","TWN":"現在這時間應該沒人會去，怎麼會？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"에잉. 한 그릇 더 먹을 생각이었는데, 이래서야 좌불안석이구만.","JPN":"はあ、もう一杯おかわりを頼むつもりじゃったが、これじゃ不安で食事もままならんのう。","ENG":"Ugh. I was about to go for another bowl, and now I cannot sit still.","TWN":"唉唷，我本來想再吃一碗，這樣真讓人坐立不安。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L3_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"그 건물. 위치나 알려주게. 음식도 대접해줬으니 겸사겸사 도와주지.","JPN":"その建物の場所を教えてくれぬか。ご馳走してもらったし、手を貸してやろう。","ENG":"Give me the location of that building. You fed me, so I will lend a hand while I am at it.","TWN":"告訴我那棟大樓的位置，既然妳都請我們吃飯了，就順便幫個忙吧。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"혼자는 위험해. 적어도 민병단원들과 같이-.","JPN":"一人じゃ危ないわ。せめて民兵団といっしょに……","ENG":"It's dangerous to go alone. At least take some from the militia with you–","TWN":"一個人行動很危險，至少也要和民兵團員一起–"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_QM","text":{"KOREA":"올가 언니. 빌렸던 만화를 돌려주러 왔어.","JPN":"オルガさん、借りてたマンガ返しに来たよ。","ENG":"Olga, I came to return the comic I borrowed.","TWN":"歐嘉姐姐，我來還之前借的漫畫。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L10_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_QM","text":{"KOREA":"그런데, 저 사람은?","JPN":"ところで、あの人は？","ENG":"Also, who is this person?","TWN":"不過，那個人是？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"응?","JPN":"うん？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"오오…!!","JPN":"おお……！！","ENG":"Ooh...!","TWN":"喔喔…！！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL"},{"id":"L15_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"이 리펄서 건. 소재, 강도, 전부 훌륭해…!!","JPN":"このリパルサーガン、素材も強度も素晴らしい……！！","ENG":"This Repulsor Gun... The material, the strength is all excellent...!!","TWN":"這把掌心槍，材料、強度都很不錯…！！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L16_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"이 무기, 네가 만든 거냐?","JPN":"この武器はお主が作ったのか？","ENG":"Did you make this weapon?","TWN":"這武器是妳做的嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_QM","text":{"KOREA":"이건… 내가 만든 게 아냐. 친구에게 배운 기술로 조금 개량한 건 맞지만.","JPN":"これは……私が作ったものじゃない。友だちに教えてもらった技術でちょっと改良しただけ。","ENG":"I didn't make it from scratch. I just tweaked it with techniques I learned from a friend.","TWN":"這個…不是我做的，但我的確是用從朋友那裡學到的技術稍微改良了一下。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"충분해! 요즘 시대에 이런 젊은이가 남아있다니!","JPN":"十分じゃ！　今の時代にまだこんな若者が残っていたとは！","ENG":"Good enough! To think there are still youngsters like you in this day and age!","TWN":"夠了！最近這時代居然還有這種年輕人！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"혹시 대장장이가 될 생각은 없나? 네 녀석의 재능은 분명 용광로 앞에서 빛날 거다!","JPN":"もしやお主、鍛冶屋になる気はないか？　お主の才能はきっと溶鉱炉の前で輝くぞ！","ENG":"Ever thought about becoming a blacksmith? Your talent would shine in front of the forge!","TWN":"妳有沒有想過要當鐵匠？妳的才能肯定能在熔鐵爐前面大放光芒！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"미안하지만, 우리 단원을 영입하려는 행위는 삼가줬으면 좋겠군.","JPN":"悪いが、うちの団員をスカウトするのは止めてもらいたい。","ENG":"Sorry, but please refrain from trying to recruit one of our members.","TWN":"抱歉，但希望妳不要做出想挖角我們團員的行為。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"마브카. 조금 전에 연구소에 문제가 생겼다.","JPN":"マブカ。少し前に研究所に問題が発生した。","ENG":"Mavka, the lab just had an issue.","TWN":"瑪卡，剛才研究所出了點問題。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"출입금지 구역, 기억하지? 괜찮다면 상황을 봐줄 수 있을까?","JPN":"立入禁止エリア、覚えているだろう？　よかったら様子を見に行ってくれないか。","ENG":"You remember the off-limits zone, right? If you can, go check it out.","TWN":"禁止進入區域，妳記得吧？可以的話能去看看情況嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"응. 문제없어.","JPN":"うん、問題ない。","ENG":"Sure. No problem.","TWN":"嗯，沒問題。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L28_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"혼자 가면 돼?","JPN":"一人で行けばいい？","ENG":"Should I go alone?","TWN":"我能一個人去嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"자넨 아직 어리니 가능성이 충분해! 하루 네 시간! 아니, 세 시간 삼십분만 할애해라!","JPN":"お主はまだ若いから無限の可能性がある！　1日4時間！　いや、3時間30分だけでいいのじゃ！","ENG":"You are still young and full of possibilities! Four hours daily! No, three and a half!","TWN":"妳年紀還小，有足夠的可能性！一天四小時！不，只要花三小時半就好！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"제발 이쪽을 봐다오…!!","JPN":"頼むからわしを見てくれ……！！","ENG":"Please, just look my way...!","TWN":"拜託看看這邊…！！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L32_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"……그전에, 이 사람을 떨어트려줬으면 좋겠는데.","JPN":"……その前に、この人を引き離してほしい。","ENG":"...Before that, I would appreciate it if you put this person down.","TWN":"……在那之前，希望能把這個人打倒。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L36_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"이, 일단 우릴 도와준다고 한 카운터야.","JPN":"い、一応、私たちに協力してくれるカウンターよ。","ENG":"S-she's a Counter who offered to help us, for the record.","TWN":"首、首先是說要幫我們的制裁者。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"강하니까 분명 도움이 될 거라 생각해.","JPN":"強いからきっと力になってくれるわ。","ENG":"She's strong, so I'm sure she'll be useful.","TWN":"她很強，我覺得肯定會有幫助。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"하아…….","JPN":"はあ……","ENG":"*Sigh...*","TWN":"唉……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"알겠어, 올가 언니 말이니까 믿을게.","JPN":"わかった。オルガさんの言うことだから信じるよ。","ENG":"All right. Since it's you, Olga, I'll trust her.","TWN":"知道了，我會相信歐嘉姐姐說的話。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"오오-. 내 손을 잡다니, 대장장이의 길에 흥미라도 생긴 게냐?","JPN":"おお、わしの手を握ってくれるとは。鍛冶屋の道に興味が湧いてきたのか？","ENG":"Ooh... You took my hand. Have you perhaps taken a shine to the way of the blacksmith?","TWN":"喔喔–居然要和我聯手，難道是對鐵匠這條路感興趣了？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_03"},{"id":"L43_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"바로 그거다, 소녀! 이렇게 된 거, 나랑 같이 도장이라도","JPN":"そうじゃ、少女よ！　こうなったからには、わしと道場でも……","ENG":"That's it, girl! In that case, why not come to the forge with me and–","TWN":"就是那個，少女！既然這樣，就和我一起去蓋個章…"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"오오오오옥–––––?!!","JPN":"おおおおおおっ─────！？","ENG":"Ooooooh–––––?!","TWN":"喔喔喔喔喔–––––？！！"},"stage":{"bg":"SKY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_MISSILE_FIRE"},{"id":"L48_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_ON","text":{"KOREA":"다녀올게.","JPN":"行ってくる。","ENG":"I'll be back.","TWN":"我要出發了。"},"stage":{"bg":"SKY","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_ON","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_04"},{"id":"L50_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"끄응… 이것 참, 요즘 젊은이들은 기운이 넘치는군.","JPN":"ぐぬぬ……まったく、最近の若者は血気盛んじゃのう。","ENG":"Oof... Kids these days are bursting with energy.","TWN":"呃嗯…這真是，最近的年輕人都精力充沛呢。"},"stage":{"bg":"SKY","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_ON","face":"UNIT_IDLE"},"R":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L1_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"설마 이 나이에 공주님 안기를 당할 줄이야.","JPN":"この歳になってお姫様抱っこされるとは。","ENG":"To think I would get princess-carried at my age.","TWN":"沒想到這個年紀還會被公主抱。"},"stage":{"bg":"SKY","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_ON","face":"UNIT_IDLE"},"R":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L3_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"별로, 나이 차이는 안 날 거라 생각해.","JPN":"そんなに歳の差はないと思うよ。","ENG":"I doubt the age gap is that big.","TWN":"我覺得年紀沒差多少。"},"stage":{"bg":"SKY","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L4_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"쯧쯔. 겉모습으로 판단하면 쓰나. 이래봬도 호랑이가 담배 피던 시절부터 살았다고.","JPN":"ええい、人を見た目で判断するのはよくないぞ。こう見えてかなり長いこと生きておるのじゃ。","ENG":"Tsk, tsk. Do not judge by appearances. I have been around since back when tigers smoked pipes.","TWN":"嘖嘖，怎麼能用外表來判斷呢？別看我這樣，我從盤古開天闢地的時候就活著了。"},"stage":{"bg":"SKY","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L5_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"그립구만~. 그땐 불가마의 대장장이라고 하면 모르는 사람이 없었는데.","JPN":"懐かしいのう～あの頃は火窯の鍛冶屋といえば、知らぬ者はいなかったんじゃが。","ENG":"Those were the days. Everyone knew who you meant when you said, \\"the forge-master of the kilns.\\"","TWN":"真懷念～那時候一說火爐的鐵匠可是人盡皆知。"},"stage":{"bg":"SKY","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"이름. 길지 않아?","JPN":"名前、長くない？","ENG":"Your name. Isn't it too long?","TWN":"不覺得名字很長嗎？"},"stage":{"bg":"SKY","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"이름이 아니라 별호다. 본명은 나오라는 아주 짧고 간결한 이름이라고.","JPN":"名前じゃなくて二つ名じゃ。本命はナオという、いとも短く簡単な名じゃぞ。","ENG":"That is not my name, it is an epithet. My real name is Nao, short and neat.","TWN":"不是名字而是綽號，我的本名叫奈緒，是個很簡潔的名字。"},"stage":{"bg":"SKY","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"그러고보니 통성명이 아직이었구나. 우리 미래의 제자님은 이름이 어떻게 되지?","JPN":"そういえばまだ名乗っていなかったか。未来の弟子よ、お主の名はなんという？","ENG":"Come to think of it, we have not exchanged names. What is my future apprentice called?","TWN":"這樣一說，我們還沒互相自我介紹，我們未來的徒弟叫什麼名字？"},"stage":{"bg":"SKY","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L12_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_ON","text":{"KOREA":"난 별로, 그쪽 제자가 될 생각은 없지만…….","JPN":"私は別に、あなたの弟子になるつもりはないけど……","ENG":"I don't really plan on becoming your apprentice...","TWN":"雖然我沒有很想成為妳的徒弟……"},"stage":{"bg":"SKY","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_ON","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_21"},{"id":"L14_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_ON","text":{"KOREA":"내 이름은 마브카 가가리나.","JPN":"私の名前はマブカ・ガガリナ。","ENG":"But my name is Mavka Gagarina.","TWN":"我的名字叫瑪卡·加格林娜。"},"stage":{"bg":"SKY","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_ON","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L15_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_ON","text":{"KOREA":"성은, 친구의 이름을 멋대로 빌린 거야.","JPN":"名字は、友だちのものを勝手に借りている。","ENG":"The last name, I borrowed from a friend.","TWN":"姓氏是隨便借用朋友的名字。"},"stage":{"bg":"SKY","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_ON","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};